// Economics & methods question bank (1116 problems) compiled from the lecture-notes
// .tex/.md sources, the International Trade notes (trade.tex), and the Part IIB Tripos
// past-paper PDFs (exam papers + study aids, 2021-2025) in reference_images/latex/ via
// that folder's build-problems.mjs. Some Development / Public Economics formulae are
// canonical forms inferred from prose-only study aids (models named but not typeset).
// Fully audited (equations + contexts) 2026-07-06; every problem carries a `context`
// (1-2 sentence plain-English interpretation) and an auto-generated `hints` array.
// Points (1-20) are BANDED by difficulty: easy 1-4, medium 5-11, hard 12-20. Within
// each band a fixed complexity index (see build-problems.mjs) ranks problems, so the
// difficulty label drives the mark. A few labels are hand-corrected via
// DIFFICULTY_OVERRIDES in build-problems.mjs. Re-copy after rebuild.
// NOTE: `npm run import` regenerates this file from questions.txt and will
// overwrite it — sync questions.txt (or re-copy from reference_images/latex/) first.
export type Difficulty = "easy" | "medium" | "hard";

export interface Hint {
  command: string; // what the player types, e.g. String.raw`\tilde{ }`
  name: string; // friendly label, e.g. "tilde accent"
  example: string; // renderable KaTeX snippet for a glyph preview
}

export interface Problem {
  id: string;
  title: string;
  latex: string;
  difficulty: Difficulty;
  points: number;
  topic: string;
  context: string; // 1-2 sentence plain-English interpretation (may be empty)
  hints: Hint[]; // notable commands in the target, trickiest-first (may be empty)
}

